/**
 * Input 样式（与 @tdesign/uniapp 视觉对齐：列表内嵌型、下分割线、状态色）
 * 全部颜色 / 间距走 CSS Variables，命名沿用 --td-input-* 系列。
 */

// ------- 默认 token -------
@td-input-vertical-padding: var(--td-input-vertical-padding, 16px);
@td-input-horizontal-padding: var(--td-input-horizontal-padding, 16px);

@td-input-bg-color: var(--td-input-bg-color, #ffffff);
@td-input-text-color: var(--td-input-default-text-color, #181818);
@td-input-disabled-text-color: var(--td-input-disabled-text-color, #c0c0c0);
@td-input-placeholder-text-color: var(--td-input-placeholder-text-color, #c0c0c0);

@td-input-label-color: var(--td-input-label-text-color, #181818);
@td-input-suffix-text-color: var(--td-input-suffix-text-color, #181818);
@td-input-suffix-icon-color: var(--td-input-suffix-icon-color, #c0c0c0);
@td-input-prefix-icon-color: var(--td-input-prefix-icon-color, #181818);

@td-input-border-color: var(--td-input-border-color, #e7e7e7);
@td-input-border-left-space: var(--td-input-border-left-space, 16px);
@td-input-border-right-space: var(--td-input-border-right-space, 0);
@td-input-align-items: var(--td-input-align-items, center);

@td-input-success-color: var(--td-input-success-tips-color, #2ba471);
@td-input-warning-color: var(--td-input-warning-tips-color, #ed7b2f);
@td-input-error-color: var(--td-input-error-tips-color, #d54941);

@td-input-label-min-width: var(--td-input-label-min-width, 32px);
@td-input-label-max-width: var(--td-input-label-max-width, 80px);

.t-input {
  display: flex;
  align-items: @td-input-align-items;
  flex: 1;
  width: 100%;
  padding: @td-input-vertical-padding @td-input-horizontal-padding;
  background-color: @td-input-bg-color;
  box-sizing: border-box;
  position: relative;
  overflow: hidden;

  // ---- 下分割线（borderless=false 时） ----
  &--border::after {
    content: '';
    position: absolute;
    left: @td-input-border-left-space;
    right: @td-input-border-right-space;
    bottom: 0;
    height: 1px;
    background-color: @td-input-border-color;
    transform: scaleY(0.5);
    transform-origin: 0 100%;
  }

  // ---- 竖排 ----
  &--layout-vertical {
    flex-direction: column;
    align-items: flex-start;
  }

  // ---- prefix 区（icon + label） ----
  &__wrap--prefix {
    display: flex;
    align-items: center;
  }

  &__icon--prefix {
    display: flex;
    align-items: center;
    color: @td-input-prefix-icon-color;
    font-size: 24px;

    &:empty {
      display: none;
    }
  }

  &__label {
    color: @td-input-label-color;
    font-size: 16px;
    line-height: 24px;
    word-wrap: break-word;
    min-width: @td-input-label-min-width;
    max-width: @td-input-label-max-width;
    margin-right: 8px;

    &:empty {
      display: none;
    }
  }

  &--layout-vertical &__label {
    font-size: 14px;
    padding-bottom: 4px;
    margin-right: 0;
  }

  // ---- 内容主体 wrap ----
  &__wrap {
    display: flex;
    flex-direction: column;
    flex: 1;
    flex-shrink: 1;
    min-width: 0;
    width: 100%;
  }

  &__content {
    display: flex;
    align-items: center;
    width: 100%;
    font-size: 16px;
    line-height: 24px;
  }

  // ---- input 控件 ----
  &__control {
    flex: 1;
    display: block;
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    min-height: 24px;
    margin: 0;
    padding: 0;
    border: 0;
    background: transparent;
    color: @td-input-text-color;
    font-size: inherit;
    line-height: inherit;

    &--disabled {
      color: @td-input-disabled-text-color;
      cursor: not-allowed;
    }

    &--read-only {
      cursor: default;
    }
  }

  &__placeholder {
    color: @td-input-placeholder-text-color;
    font-size: 16px;

    &--disabled {
      color: @td-input-disabled-text-color;
    }
  }

  // ---- 文本对齐 ----
  &--left   { text-align: left; }
  &--center { text-align: center; }
  &--right  { text-align: right; }

  // ---- 后置区域 ----
  &__wrap--clearable-icon,
  &__wrap--suffix-icon,
  &__wrap--suffix {
    flex: 0 0 auto;
    padding-left: 4px;
    display: flex;
    align-items: center;

    &:empty {
      display: none;
    }
  }

  &__wrap--clearable-icon,
  &__wrap--suffix-icon {
    color: @td-input-suffix-icon-color;
    font-size: 24px;
  }

  &__wrap--suffix {
    color: @td-input-suffix-text-color;
    font-size: 14px;
  }

  // 兜底的 ✕（无 t-icon 时使用）
  &__clear-fallback {
    width: 16px;
    height: 16px;
    line-height: 14px;
    text-align: center;
    border-radius: 50%;
    background: #c5c5c5;
    color: #ffffff;
    font-size: 12px;
  }

  // ---- tips ----
  &__tips {
    font-size: 12px;
    line-height: 18px;
    padding-top: 4px;

    &.t-input--default { color: @td-input-placeholder-text-color; }
    &.t-input--success { color: @td-input-success-color; }
    &.t-input--warning { color: @td-input-warning-color; }
    &.t-input--error   { color: @td-input-error-color; }
  }

  // ---- 禁用 / 只读 ----
  &--disabled .t-input__control,
  &--readonly .t-input__control {
    color: @td-input-disabled-text-color;
  }
}

/**
 * Input 组件类型契约
 *
 * 与 @tdesign/uniapp 的 input 组件 API 对齐：
 * https://tdesign.tencent.com/uniapp/components/input
 */

/** 输入框类型 */
export type InputType =
  | 'text'
  | 'number'
  | 'idcard'
  | 'digit'
  | 'safe-password'
  | 'password'
  | 'nickname';

/** 校验状态（影响 tips 文字色） */
export type InputStatus = 'default' | 'success' | 'warning' | 'error';

/** 文字对齐 */
export type InputAlign = 'left' | 'center' | 'right';

/** 标签布局 */
export type InputLayout = 'horizontal' | 'vertical';

/** 清除图标触发方式 */
export type InputClearTrigger = 'always' | 'focus';

/** 键盘右下角按钮文字 */
export type InputConfirmType = 'send' | 'search' | 'next' | 'go' | 'done';

/** change 事件参数 */
export interface InputChangePayload {
  value: string;
  cursor?: number;
  keyCode?: number;
}

/** click 事件参数 */
export interface InputClickPayload {
  /** 触发来源 */
  trigger: 'input' | 'suffix' | 'suffix-icon';
}

/** 格式化函数 */
export type InputFormatFn = (value: string) => string;

export interface InputProps {
  /** v-model 同步值（受控） */
  modelValue?: string;
  /** 与 modelValue 同义，兼容 uniapp 版的 `value` 命名 */
  value?: string;
  /** 占位符 */
  placeholder?: string;
  /** 输入框类型 */
  type?: InputType;
  /** 文本对齐方式 */
  align?: InputAlign;
  /** 标签 */
  label?: string;
  /** 输入框下方提示文本（受 status 影响色彩） */
  tips?: string;
  /** 后置文本（位于 suffix-icon 之前） */
  suffix?: string;
  /** 前置图标名（字符串）；如需更复杂结构请使用 prefix-icon slot */
  prefixIcon?: string;
  /** 后置图标名（字符串）；如需更复杂结构请使用 suffix-icon slot */
  suffixIcon?: string;
  /** 标签 + 输入框布局 */
  layout?: InputLayout;
  /** 是否无下边框 */
  borderless?: boolean;
  /** 校验状态 */
  status?: InputStatus;
  /** 是否禁用 */
  disabled?: boolean;
  /** 是否只读 */
  readonly?: boolean;
  /** 是否显示清除按钮 */
  clearable?: boolean;
  /** 清除按钮触发条件 */
  clearTrigger?: InputClearTrigger;
  /** 最大长度；-1 不限制 */
  maxlength?: number;
  /** 最大字符数（一个汉字算 2）；-1 不限制；与 maxlength 二选一 */
  maxcharacter?: number;
  /** 超出 maxlength/maxcharacter 是否仍允许继续输入 */
  allowInputOverMax?: boolean;
  /** 自动获取焦点 */
  focus?: boolean;
  /** 键盘右下角按钮文字 */
  confirmType?: InputConfirmType;
  /** 点击键盘右下角按钮时是否保持键盘不收起 */
  confirmHold?: boolean;
  /** 键盘弹起时是否自动上推页面 */
  adjustPosition?: boolean;
  /** 占位符样式类 */
  placeholderClass?: string;
  /** 占位符样式 */
  placeholderStyle?: string;
  /** 格式化函数（失焦时执行） */
  format?: InputFormatFn;
  /** 透传额外类名 */
  customClass?: string;
}

export interface InputEmits {
  (e: 'update:modelValue', value: string): void;
  (e: 'update:value', value: string): void;
  (e: 'change', payload: InputChangePayload): void;
  (e: 'focus', payload: { value: string }): void;
  (e: 'blur', payload: { value: string; cursor?: number }): void;
  (e: 'clear', payload: { value: string }): void;
  (e: 'enter', payload: { value: string }): void;
  (e: 'click', payload: InputClickPayload): void;
  (e: 'keyboardheightchange', payload: { height: number; duration: number }): void;
  (e: 'nicknamereview', payload: { pass: boolean; timeout: boolean }): void;
}

import { cva } from '../../utils/cva';

/**
 * Input 根容器的变体（与 @tdesign/uniapp 对齐）：
 *  - layout：horizontal / vertical
 *  - align：left / center / right（用于 input 文字对齐）
 *  - status：default / success / warning / error
 *  - borderless：true 去除底部分割线
 *  - disabled / readonly
 */
export const inputVariants = cva('t-input', {
  variants: {
    layout: {
      horizontal: 't-input--layout-horizontal',
      vertical: 't-input--layout-vertical',
    },
    align: {
      left: 't-input--left',
      center: 't-input--center',
      right: 't-input--right',
    },
    status: {
      default: 't-input--default',
      success: 't-input--success',
      warning: 't-input--warning',
      error: 't-input--error',
    },
    borderless: {
      true: '',
      false: 't-input--border',
    },
    disabled: { true: 't-input--disabled' },
    readonly: { true: 't-input--readonly' },
  },
  defaultVariants: {
    layout: 'horizontal',
    align: 'left',
    status: 'default',
    borderless: false,
  },
});

/**
 * input control（真正的 <input>）的类名（受 align / disabled 影响）
 */
export const inputControlVariants = cva('t-input__control', {
  variants: {
    align: {
      left: 't-input--left',
      center: 't-input--center',
      right: 't-input--right',
    },
    disabled: { true: 't-input__control--disabled' },
    readonly: { true: 't-input__control--read-only' },
  },
  defaultVariants: {
    align: 'left',
  },
});

/**
 * tips 节点的类名（受 align / status 影响）
 */
export const inputTipsVariants = cva('t-input__tips', {
  variants: {
    align: {
      left: 't-input--left',
      center: 't-input--center',
      right: 't-input--right',
    },
    status: {
      default: 't-input--default',
      success: 't-input--success',
      warning: 't-input--warning',
      error: 't-input--error',
    },
  },
  defaultVariants: {
    align: 'left',
    status: 'default',
  },
});
